/**
 * Internal Medicine shelf MCQ bank — single-best-answer questions for the IM
 * shelf. The base set was written + adversarially fact-checked, then upgraded to
 * teaching-mode (per-option rationales + concept blocks) and EXPANDED with new
 * items generated from a high-yield IM review (MehlmanMedical HY Internal
 * Medicine) and fact-checked. Grouped by organ system for focused cramming.
 *
 * Style matches the OB/FM banks: quick single-best-answer vignettes with
 * teaching-mode explanations. Existing items keep their original option order
 * (rationales are aligned to it); newly generated items are pre-shuffled
 * (stem-seeded, deterministic) so the key spreads across A-E; the screen
 * reshuffles at runtime and carries each option's rationale with it.
 *
 * GENERATED FILE (JSON -> TS build). Do not hand-edit; re-run the build.
 *
 * Educational use only — confirm dosing and current guidelines.
 */

export interface McqQuestion {
  id: string;
  /** Organ system — drives grouping + the filter. */
  system: string;
  /** Short 2-5 word label of what the item tests. */
  topic: string;
  /** Clinical-vignette stem ending in a single-best-answer lead-in. */
  stem: string;
  /** 4-5 answer options. */
  options: string[];
  /** 0-based index of the single best answer. */
  answerIndex: number;
  /** Why the key is right + why the best distractor is wrong. */
  explanation: string;
  /**
   * Optional teaching-mode extras (present on the Family Medicine bank). All
   * optional so banks without them render the classic explanation-only view.
   */
  /** One sentence per option, aligned 1:1 to `options` — why right / why wrong / when it'd be right. */
  optionRationales?: string[];
  /** 2-4 sentence generalizable teaching point for the concept. */
  concept?: string;
  /** Compact "threshold → action" bullets for guideline/score topics (omitted otherwise). */
  conceptRule?: string[];
  /** What a named score/scale is composed of (e.g. Wells criteria), when one is central. */
  scoreComponents?: string[];
  /** One line naming the feature that clinches the answer over its nearest mimic. */
  discriminator?: string;
  /** A standard mnemonic for the concept, when a well-known one exists. */
  mnemonic?: string;
}

